const float b2[10] = {1.840553000e-01, 9.899160000e-03, -8.615120000e-01, -8.599189000e-01, 2.169557000e-01, -9.662905000e-01, 4.923897000e-01, -1.028381000e+00, 2.061140000e+00, 6.046520000e-01};
const float w2_scales[10] = {6.382764567e-03f, 9.551606299e-03f, 1.012522835e-02f, 8.273858268e-03f, 9.170275591e-03f, 9.403748031e-03f, 7.886850394e-03f, 8.997118110e-03f, 9.192354331e-03f, 1.100330709e-02f};

static inline void predict_int8(const float* input, float* output) {
    float a[128], b[128];
    float logits[128];
    const float* in = input;
    float* out = a;

    // layer 1 (relu) - INT8 SYMMETRIC QUANTIZED
    for (int i = 0; i < 128; i++) {
        float dot_product = 0.0f;
        for (int j = 0; j < 784; j++) {
            dot_product += (float)w1[i][j] * in[j];
        }
        float sum = b1[i] + (dot_product * w1_scales[i]);
        out[i] = relu(sum);
    }
    in = out; out = (out == a) ? b : a;

    // layer 2 (softmax) - INT8 SYMMETRIC QUANTIZED
    for (int i = 0; i < 10; i++) {
        float dot_product = 0.0f;
        for (int j = 0; j < 128; j++) {
            dot_product += (float)w2[i][j] * in[j];
        }
        logits[i] = b2[i] + (dot_product * w2_scales[i]);
    }
    float max_logit = logits[0];
    for (int i = 1; i < 10; i++) {
        if (logits[i] > max_logit)
            max_logit = logits[i];
    }
    float exp_sum = 0.0f;
    for (int i = 0; i < 10; i++) {
        out[i] = expf(logits[i] - max_logit);
        exp_sum += out[i];
    }
    for (int i = 0; i < 10; i++) {
        out[i] /= exp_sum;
    }

    for (int i = 0; i < 10; i++)
        output[i] = out[i];
}

// Wrapper: predict() delegates to predict_int8()
static inline void predict(const float* input, float* output) {
    predict_int8(input, output);
}

